buggy_code:
def sum_even_numbers(values: list[int]) -> int:
    total = 0
    for value in values:
        if value % 2 == 1:
            total += value
    return total

canonical_fix:
def sum_even_numbers(values: list[int]) -> int:
    total = 0
    for value in values:
        if value % 2 == 0:
            total += value
    return total
